use std::io::{self, prelude::*};


#[allow(unused_must_use)]
#[allow(unused_assignments)]
#[allow(unused_variables)]
fn solve<B: BufRead, W: Write>(mut scan: Scanner<B>, mut w: W) {
    let k = scan.token::<usize>();
    let l = scan.token::<usize>();
    let m = scan.token::<usize>();
    let n = scan.token::<usize>();
    let d = scan.token::<usize>();

    let mut arr = vec![false; d];

    for i in (0..d).skip(k-1).step_by(k) {
        arr[i] = true;
    }
    for i in (0..d).skip(l-1).step_by(l) {
        arr[i] = true;
    }
    for i in (0..d).skip(m-1).step_by(m) {
        arr[i] = true;
    }
    for i in (0..d).skip(n-1).step_by(n) {
        arr[i] = true;
    }

    let ans: usize = arr.iter().filter(|&e| *e).count();

    writeln!(w, "{}", ans);
}

fn main() {
    let stdin = io::stdin();
    let stdout = io::stdout();
    let reader = Scanner::new(stdin.lock());
    let writer = io::BufWriter::new(stdout.lock());
    solve(reader, writer);
}
